/* ==========================================================================
   Select — combobox-pattern select using ds-menu for the dropdown.
   ========================================================================== */

@import '../../utils/control-inactive.css';

:host(.select-host) {
  display: inline-block;
  width: 100%;
  position: relative;
}

/* Inactive: `.ds-control-inactive` (25% opacity). */

/* ── Trigger button ──────────────────────────────────────────────────────── */

.trigger {
  display: inline-flex;
  align-items: center;
  justify-content: space-between;
  width: 100%;
  height: var(--dimension-size-400);
  padding: 0 var(--dimension-space-075) 0 var(--dimension-space-100);
  border: none;
  border-radius: var(--dimension-radius-050);
  background-color: var(--color-background-primary);
  box-shadow: var(--effect-elevation-elevated-sm);
  cursor: pointer;
  box-sizing: border-box;
  gap: var(--dimension-space-050);
  font-family: inherit;
  outline: none;

  --_hover-bg: color-mix(in oklch, var(--color-background-primary) 90%, var(--color-foreground-primary));
  --_pressed-bg: color-mix(in oklch, var(--color-background-primary) 85%, var(--color-foreground-primary));
}

.trigger:focus-visible {
  outline: var(--dimension-stroke-width-025) solid var(--color-interaction-focus);
  outline-offset: var(--dimension-space-025);
}

.trigger:hover:not(:disabled) {
  background-color: var(--_hover-bg);
}

.trigger:active:not(:disabled) {
  background-color: var(--_pressed-bg);
}

.trigger--open {
  background-color: var(--_pressed-bg);
}

/* ── Trigger label ───────────────────────────────────────────────────────── */

.trigger__label {
  flex: 1;
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  text-align: left;
  font-size: var(--typography-fontsize-md);
  line-height: var(--typography-lineheight-md);
  font-weight: var(--typography-weight-regular);
  color: var(--color-foreground-primary);
}

.trigger__label--placeholder {
  color: var(--color-foreground-secondary);
}

/* ── Chevron icon ────────────────────────────────────────────────────────── */

.trigger__chevron {
  flex-shrink: 0;
  color: var(--color-foreground-secondary);
  transition: transform var(--effect-motion-short-2);
}

.trigger--open .trigger__chevron {
  transform: rotate(180deg);
}

import { Component, Prop, State, Event, EventEmitter, Element, Watch, Listen, h, Host } from '@stencil/core';
import type { MenuItemData } from '../Menu/menu-types';

export interface SelectOption {
  label: string;
  value: string;
}

@Component({
  tag: 'ds-select',
  styleUrl: 'Select.css',
  scoped: true,
})
export class Select {
  @Element() el!: HTMLElement;

  /**
   * Array of options. Set via JS property.
   * @example el.options = [{ label: 'Apple', value: 'apple' }];
   */
  @Prop() options: SelectOption[] = [];

  /** Currently selected value. */
  @Prop({ mutable: true }) value: string = '';

  /** Placeholder shown when no value is selected. */
  @Prop() placeholder: string = 'Select option';

  /** Disables interaction (25% opacity via ds-control-inactive). */
  @Prop() isInactive: boolean = false;

  @Prop({ attribute: 'aria-label' }) ariaLabel: string | undefined;
  @Prop({ attribute: 'aria-labelledby' }) ariaLabelledby: string | undefined;

  /** Emits the selected value string. */
  @Event() dsChange!: EventEmitter<string>;

  @State() private isOpen: boolean = false;

  private triggerEl: HTMLButtonElement | null = null;
  private menuEl: HTMLDsMenuElement | null = null;

  componentDidLoad() {
    // Wire up the menu anchor to the trigger button
    if (this.menuEl && this.triggerEl) {
      this.menuEl.anchor = this.triggerEl;
    }
    // Listen for menu selection events
    this.menuEl?.addEventListener('dsSelect', (e: Event) => {
      const detail = (e as CustomEvent<MenuItemData>).detail;
      if (detail?.value !== undefined) {
        this.value = String(detail.value);
        this.dsChange.emit(this.value);
      }
      this.isOpen = false;
    });
    // Listen for menu close event
    this.menuEl?.addEventListener('dsClose', () => {
      this.isOpen = false;
    });
  }

  @Watch('isOpen')
  onIsOpenChange(open: boolean) {
    if (this.menuEl) {
      this.menuEl.open = open;
    }
  }

  @Watch('options')
  onOptionsChange() {
    this.syncMenuItems();
  }

  @Watch('value')
  onValueChange() {
    this.syncMenuItems();
  }

  private syncMenuItems() {
    if (!this.menuEl) return;
    this.menuEl.items = this.options.map(opt => ({
      label: opt.label,
      value: opt.value,
      isSelected: opt.value === this.value,
    }));
  }

  private open() {
    if (this.isInactive || !this.options.length) return;
    // Sync menu width to trigger width
    if (this.menuEl && this.triggerEl) {
      this.menuEl.menuWidth = `${this.triggerEl.offsetWidth}px`;
      this.menuEl.anchor = this.triggerEl;
    }
    this.syncMenuItems();
    this.isOpen = true;
  }

  private close() {
    this.isOpen = false;
  }

  private toggle() {
    if (this.isOpen) {
      this.close();
    } else {
      this.open();
    }
  }

  @Listen('keydown')
  handleKeyDown(e: KeyboardEvent) {
    // Only handle keydown on the trigger button
    if (document.activeElement !== this.triggerEl) return;

    if (!this.isOpen) {
      switch (e.key) {
        case 'ArrowDown':
        case 'ArrowUp':
        case 'Enter':
        case ' ':
          e.preventDefault();
          this.open();
          break;
      }
    } else {
      if (e.key === 'Escape') {
        e.preventDefault();
        this.close();
        this.triggerEl?.focus();
      }
    }
  }

  private get selectedLabel(): string {
    const found = this.options.find(o => o.value === this.value);
    return found?.label ?? '';
  }

  private get hasSelection(): boolean {
    return !!this.options.find(o => o.value === this.value);
  }

  render() {
    const label = this.hasSelection ? this.selectedLabel : this.placeholder;
    const showPlaceholder = !this.hasSelection;

    return (
      <Host class={{ 'select-host': true, 'ds-control-inactive': this.isInactive }}>
        <button
          ref={el => {
            this.triggerEl = (el as HTMLButtonElement) ?? null;
          }}
          type="button"
          class={{ trigger: true, 'trigger--open': this.isOpen }}
          disabled={this.isInactive}
          role="combobox"
          aria-haspopup="listbox"
          aria-expanded={this.isOpen}
          aria-label={this.ariaLabel}
          aria-labelledby={this.ariaLabelledby}
          onClick={() => this.toggle()}
        >
          <span class={{ 'trigger__label': true, 'trigger__label--placeholder': showPlaceholder }}>
            {label}
          </span>
          <svg
            class="trigger__chevron"
            width="16"
            height="16"
            viewBox="0 0 16 16"
            fill="none"
            aria-hidden="true"
          >
            <path
              d="M4 6L8 10L12 6"
              stroke="currentColor"
              stroke-width="1.25"
              stroke-linecap="round"
              stroke-linejoin="round"
            />
          </svg>
        </button>
        <ds-menu
          ref={el => {
            this.menuEl = (el as HTMLDsMenuElement) ?? null;
          }}
          side="bottom"
          align="start"
        />
      </Host>
    );
  }
}
